#include <stdio.h>
#include <string.h>

int dayIndex(const char *s) {
    if (strcmp(s, "mon") == 0) return 0;
    if (strcmp(s, "tues") == 0) return 1;
    if (strcmp(s, "wed") == 0) return 2;
    if (strcmp(s, "thurs") == 0) return 3;
    if (strcmp(s, "fri") == 0) return 4;
    if (strcmp(s, "sat") == 0) return 5;
    return 6; // sun
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int W; char S[10];
        scanf("%d %s", &W, S);
        int base = W / 7;
        int r = W % 7;
        int cnt[7];
        for (int i = 0; i < 7; ++i) cnt[i] = base;
        int start = dayIndex(S);
        for (int i = 0; i < r; ++i) cnt[(start + i) % 7]++;
        for (int i = 0; i < 7; ++i) {
            if (i) printf(" ");
            printf("%d", cnt[i]);
        }
        printf("\n");
    }
    return 0;
}

