#!/usr/bin/env python3
import sys

def idx(day):
    return {"mon":0,"tues":1,"wed":2,"thurs":3,"fri":4,"sat":5,"sun":6}[day]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    pos = 1
    out_lines = []
    for _ in range(t):
        W = int(data[pos]); S = data[pos+1]; pos += 2
        base, r = divmod(W, 7)
        cnt = [base]*7
        start = idx(S)
        for i in range(r):
            cnt[(start+i)%7] += 1
        out_lines.append(' '.join(map(str,cnt)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

